module RefModule (
    input wire clk,
    input wire rst_n,
    input wire start_tx,
    input wire ack_received,
    output reg [1:0] state
);
    // State encoding
    parameter IDLE = 2'b00;
    parameter TRANSMIT = 2'b01;
    parameter WAIT_FOR_ACK = 2'b10;

    // State register
    reg [1:0] ctrl_bus_wire;

    // State transition logic
    always @(*) begin
        case (state)
            IDLE: begin
                if (start_tx) 
                    ctrl_bus_wire = TRANSMIT;
                else 
                    ctrl_bus_wire = IDLE;
            end
            TRANSMIT: begin
                ctrl_bus_wire = WAIT_FOR_ACK; // Assume transmission is always complete
            end
            WAIT_FOR_ACK: begin
                if (ack_received) 
                    ctrl_bus_wire = IDLE;
                else 
                    ctrl_bus_wire = WAIT_FOR_ACK;
            end
            default: ctrl_bus_wire = IDLE;
        endcase
    end

    // State update logic
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) 
            state <= IDLE;
        else 
            state <= ctrl_bus_wire;
    end
endmodule
